# tools/cost_model.py
from dataclasses import dataclass

@dataclass
class CostProjection:
    monthly_requests: int
    avg_input_tokens: int   # system prompt + retrieved context + user message
    avg_output_tokens: int  # Claude's response

    # Pricing as of blueprint authoring date — verify current pricing
    input_price_per_mtok: float = 3.00   # $ per million tokens (Sonnet)
    output_price_per_mtok: float = 15.00

    @property
    def monthly_input_tokens(self) -> int:
        return self.monthly_requests * self.avg_input_tokens

    @property
    def monthly_output_tokens(self) -> int:
        return self.monthly_requests * self.avg_output_tokens

    @property
    def monthly_cost_usd(self) -> float:
        input_cost = (self.monthly_input_tokens / 1_000_000) * self.input_price_per_mtok
        output_cost = (self.monthly_output_tokens / 1_000_000) * self.output_price_per_mtok
        return input_cost + output_cost

# Example: 50,000 requests/month, 2,000 input tokens, 300 output tokens
projection = CostProjection(
    monthly_requests=50_000,
    avg_input_tokens=2_000,
    avg_output_tokens=300,
)
print(f"Monthly cost: ${projection.monthly_cost_usd:,.2f}")
# Monthly cost: $525.00
